import { useState, useEffect, useCallback } from 'react';
import { api, apiPost } from '../utils/api';
import useUserBots from '../hooks/useUserBots';
import useIsMobile from '../hooks/useIsMobile';
import InfoTooltip, { getDefinition } from '../components/InfoTooltip';
import LoadingState from '../components/LoadingState';
import usePageTitle from '../hooks/usePageTitle';
import { tokens } from '../styles/tokens';
import s from './CapitalAllocationPage.module.css';

const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
};

const CLUSTER_COLORS = ['#22d3ee', '#a78bfa', '#f59e0b', '#ec4899', '#3FB950', '#F85149', '#60A5FA'];

function formatCurrency(val) {
  if (val == null) return '--';
  return new Intl.NumberFormat('en-US', {
    style: 'currency', currency: 'USD', minimumFractionDigits: 2,
  }).format(val);
}

function formatPct(val) {
  if (val == null) return '--';
  return `${(val * 100).toFixed(1)}%`;
}

function BarSegment({ pct, color, label }) {
  return pct > 0 ? (
    <div className={s.barSegment} style={{
      width: `${pct}%`, backgroundColor: color,
      minWidth: pct > 5 ? 40 : 0,
    }}>
      {pct > 8 ? `${label} ${typeof pct === 'number' ? pct.toFixed(0) : pct}%` : ''}
    </div>
  ) : null;
}

export default function CapitalAllocationPage() {
  usePageTitle('Capital Allocation');
  const isMobile = useIsMobile();
  const { bots: userBots } = useUserBots();

  const [currentAlloc, setCurrentAlloc] = useState(null);
  const [suggestions, setSuggestions] = useState(null);
  const [clusters, setClusters] = useState(null);
  const [riskBudgets, setRiskBudgets] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [runLoading, setRunLoading] = useState(false);
  const [selectedStrategy, setSelectedStrategy] = useState('');
  const [strategyDetail, setStrategyDetail] = useState(null);
  const [strategyLoading, setStrategyLoading] = useState(false);

  const fetchAll = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const [allocRes, clusterRes, budgetRes] = await Promise.allSettled([
        api('/allocator/current'),
        api('/allocator/clusters'),
        api('/accounts/risk-budgets'),
      ]);
      if (allocRes.status === 'fulfilled' && allocRes.value) setCurrentAlloc(allocRes.value);
      if (clusterRes.status === 'fulfilled' && clusterRes.value) setClusters(clusterRes.value);
      if (budgetRes.status === 'fulfilled' && budgetRes.value) setRiskBudgets(budgetRes.value);
    } catch (e) {
      setError(e.message || 'Failed to load allocation data');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchAll();
    const iv = setInterval(fetchAll, 30000);
    return () => clearInterval(iv);
  }, [fetchAll]);

  const handleRunAllocator = async () => {
    setRunLoading(true);
    try {
      const res = await apiPost('/allocator/run', {});
      if (res) setSuggestions(res);
    } catch {
      // silent
    } finally {
      setRunLoading(false);
    }
  };

  const handleStrategyLookup = async (name) => {
    if (!name) { setStrategyDetail(null); return; }
    setSelectedStrategy(name);
    setStrategyLoading(true);
    try {
      const res = await api(`/allocator/strategy/${encodeURIComponent(name)}`);
      if (res) setStrategyDetail(res);
    } catch {
      setStrategyDetail(null);
    } finally {
      setStrategyLoading(false);
    }
  };

  // Extract data from API responses
  const allocations = currentAlloc?.allocations || currentAlloc?.data?.allocations || {};
  const botNames = Object.keys(allocations);
  const totalCapital = currentAlloc?.total_capital || currentAlloc?.total_equity || 0;

  // Suggestions data
  const suggestionList = suggestions?.suggestions || suggestions?.allocations || suggestions?.data || [];
  const suggestionArray = Array.isArray(suggestionList) ? suggestionList : Object.entries(suggestionList).map(([k, v]) => ({
    name: k, ...(typeof v === 'object' ? v : { allocation: v }),
  }));

  // Clusters data
  const clusterList = clusters?.clusters || clusters?.data || clusters || [];
  const clusterArray = Array.isArray(clusterList) ? clusterList : [];

  // Risk budgets data
  const budgetData = riskBudgets?.budgets || riskBudgets?.data || riskBudgets || {};
  const budgetEntries = Array.isArray(budgetData)
    ? budgetData
    : Object.entries(budgetData).map(([k, v]) => ({ name: k, ...(typeof v === 'object' ? v : { budget: v }) }));

  // Strategy names from clusters or allocations
  const allStrategyNames = [
    ...new Set([
      ...botNames,
      ...clusterArray.flatMap(c => c.strategies || c.members || []),
    ]),
  ].filter(Boolean).sort();

  /* ===== MOBILE LAYOUT ===== */
  if (isMobile) {
    return (
      <LoadingState loading={loading} error={error} empty={!currentAlloc && !clusters} type="table" onRetry={fetchAll}>
        <div className="mobile-page">
          <div className="mobile-page-header">
            <h1>Capital Allocation</h1>
            <p>Current allocation, suggestions, and cluster analysis</p>
          </div>

          <div className="mobile-hero">
            <div className="mobile-hero-label">Total Capital</div>
            <div className="mobile-hero-value" style={{ color: totalCapital > 0 ? C.blue : C.textSecondary }}>
              {totalCapital > 0 ? formatCurrency(totalCapital) : '--'}
            </div>
          </div>

          {botNames.map(name => {
            const alloc = allocations[name];
            const pct = typeof alloc === 'object' ? (alloc.pct || alloc.weight || 0) : (alloc || 0);
            const value = typeof alloc === 'object' ? (alloc.value || alloc.equity || 0) : 0;
            return (
              <div className="mobile-card" key={name}>
                <div className={s.mobileBotHeader}>
                  <span className={s.mobileBotName} style={{ color: C.blue }}>{name}</span>
                  <span className="mobile-pill" style={{ background: `${C.blue}20`, color: C.blue }}>
                    {typeof pct === 'number' ? `${(pct > 1 ? pct : pct * 100).toFixed(1)}%` : pct}
                  </span>
                </div>
                <div className={s.mobileBotEquity}>
                  {value > 0 ? formatCurrency(value) : '--'}
                </div>
              </div>
            );
          })}
        </div>
      </LoadingState>
    );
  }

  /* ===== DESKTOP LAYOUT ===== */
  return (
    <LoadingState loading={loading} error={error} empty={!currentAlloc && !clusters && !riskBudgets} type="table" onRetry={fetchAll}>
      <div className={s.page}>
        <div className={s.header}>
          <h1 className={s.title}>Capital Allocation</h1>
          <p className={s.subtitle}>
            Current allocation across bots and strategies -- display only, never auto-executed
          </p>
        </div>

        {/* Summary Cards */}
        <div className={s.cardsRow}>
          <div className={s.statCard}>
            <div className={s.statCardLabel}>
              Total Capital{getDefinition('Total Capital') && <InfoTooltip term="Total Capital" size={11} />}
            </div>
            <div className={s.statCardValue} style={{ color: C.blue }}>
              {totalCapital > 0 ? formatCurrency(totalCapital) : '--'}
            </div>
          </div>
          {botNames.slice(0, 4).map(name => {
            const alloc = allocations[name];
            const pct = typeof alloc === 'object' ? (alloc.pct || alloc.weight || 0) : (alloc || 0);
            const value = typeof alloc === 'object' ? (alloc.value || alloc.equity || 0) : (totalCapital * (pct > 1 ? pct / 100 : pct));
            const displayPct = pct > 1 ? pct : (pct * 100);
            return (
              <div className={s.statCard} key={name}>
                <div className={s.statCardLabel}>{name}</div>
                <div className={s.statCardValue} style={{ color: C.green }}>
                  {value > 0 ? formatCurrency(value) : '--'}
                </div>
                <div className={s.statCardSubtext}>{displayPct.toFixed(1)}% of portfolio</div>
              </div>
            );
          })}
        </div>

        <div className={s.scrollArea}>
          {/* Capital Distribution Bar */}
          {botNames.length > 0 && (
            <div className={s.panel}>
              <div className={s.panelTitle}>Capital Distribution</div>
              <div className={s.distributionBar}>
                {botNames.map((name, i) => {
                  const alloc = allocations[name];
                  const pct = typeof alloc === 'object' ? (alloc.pct || alloc.weight || 0) : (alloc || 0);
                  const displayPct = pct > 1 ? pct : (pct * 100);
                  return (
                    <BarSegment
                      key={name}
                      pct={displayPct}
                      color={CLUSTER_COLORS[i % CLUSTER_COLORS.length]}
                      label={name}
                    />
                  );
                })}
              </div>
              <div className={s.legendRow}>
                {botNames.map((name, i) => {
                  const alloc = allocations[name];
                  const pct = typeof alloc === 'object' ? (alloc.pct || alloc.weight || 0) : (alloc || 0);
                  const displayPct = pct > 1 ? pct : (pct * 100);
                  return (
                    <div key={name} className={s.legendItem}>
                      <div className={s.legendDot} style={{ backgroundColor: CLUSTER_COLORS[i % CLUSTER_COLORS.length] }} />
                      <span className={s.legendText}>{name}: {displayPct.toFixed(1)}%</span>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Allocation Suggestions */}
          <div className={s.panel}>
            <div className={s.panelTitle} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
              <span>Allocation Suggestions</span>
              <button
                onClick={handleRunAllocator}
                disabled={runLoading}
                className={s.saveBtn}
                style={{ backgroundColor: C.blue, color: '#fff', fontSize: 12, padding: '8px 16px' }}
              >
                {runLoading ? 'Running...' : 'Run Allocator'}
              </button>
            </div>
            <div className={s.panelDescription}>
              AI-generated suggestions based on current performance and risk metrics. Review only -- changes are never auto-executed.
            </div>

            {suggestionArray.length > 0 ? (
              <div className={s.suggestionsTable}>
                <div className={s.suggestionsHeader}>
                  <span className={s.suggestionsCol}>Strategy / Bot</span>
                  <span className={s.suggestionsColRight}>Current</span>
                  <span className={s.suggestionsColRight}>Suggested</span>
                  <span className={s.suggestionsColRight}>Delta</span>
                  <span className={s.suggestionsColWide}>Reason</span>
                </div>
                {suggestionArray.map((sug, i) => {
                  const name = sug.name || sug.strategy || sug.bot || `Item ${i + 1}`;
                  const current = sug.current_allocation || sug.current || 0;
                  const suggested = sug.suggested_allocation || sug.suggested || sug.allocation || 0;
                  const delta = sug.delta || (suggested - current);
                  const reason = sug.reason || sug.rationale || '';
                  const currentDisplay = current > 1 ? current : current * 100;
                  const suggestedDisplay = suggested > 1 ? suggested : suggested * 100;
                  const deltaDisplay = delta > 1 ? delta : delta * 100;
                  return (
                    <div key={name + i} className={s.suggestionsRow}>
                      <span className={s.suggestionsCol} style={{ fontWeight: 600, color: C.textPrimary }}>{name}</span>
                      <span className={s.suggestionsColRight} style={{ fontFamily: tokens.font.mono }}>
                        {currentDisplay.toFixed(1)}%
                      </span>
                      <span className={s.suggestionsColRight} style={{ fontFamily: tokens.font.mono, color: C.blue }}>
                        {suggestedDisplay.toFixed(1)}%
                      </span>
                      <span className={s.suggestionsColRight} style={{
                        fontFamily: tokens.font.mono,
                        color: deltaDisplay > 0 ? C.green : deltaDisplay < 0 ? C.red : C.textSecondary,
                        fontWeight: 600,
                      }}>
                        {deltaDisplay > 0 ? '+' : ''}{deltaDisplay.toFixed(1)}%
                      </span>
                      <span className={s.suggestionsColWide} style={{ color: C.textSecondary, fontSize: 12 }}>
                        {reason}
                      </span>
                    </div>
                  );
                })}
              </div>
            ) : (
              <div className={s.emptyText}>
                No suggestions yet. Click "Run Allocator" to generate allocation recommendations.
              </div>
            )}
          </div>

          {/* Cluster Analysis */}
          <div className={s.panel}>
            <div className={s.panelTitle}>Cluster Analysis</div>
            <div className={s.panelDescription}>
              Strategies grouped by correlation and behavioral similarity.
            </div>
            {clusterArray.length > 0 ? (
              <div className={s.clusterGrid}>
                {clusterArray.map((cluster, ci) => {
                  const clusterName = cluster.name || cluster.cluster_id || `Cluster ${ci + 1}`;
                  const members = cluster.strategies || cluster.members || [];
                  const correlation = cluster.avg_correlation || cluster.correlation;
                  const risk = cluster.risk_contribution || cluster.risk;
                  const performance = cluster.avg_return || cluster.performance;
                  const color = CLUSTER_COLORS[ci % CLUSTER_COLORS.length];
                  return (
                    <div key={clusterName} className={s.clusterCard}>
                      <div className={s.clusterHeader}>
                        <div className={s.clusterDot} style={{ backgroundColor: color }} />
                        <span className={s.clusterName}>{clusterName}</span>
                        <span className={s.clusterCount}>{members.length} strategies</span>
                      </div>
                      {correlation != null && (
                        <div className={s.clusterMeta}>
                          <span>Avg Correlation:</span>
                          <span style={{ color: C.textPrimary, fontFamily: tokens.font.mono }}>
                            {typeof correlation === 'number' ? correlation.toFixed(3) : correlation}
                          </span>
                        </div>
                      )}
                      {risk != null && (
                        <div className={s.clusterMeta}>
                          <span>Risk Contribution:</span>
                          <span style={{ color: C.amber, fontFamily: tokens.font.mono }}>
                            {typeof risk === 'number' ? formatPct(risk) : risk}
                          </span>
                        </div>
                      )}
                      {performance != null && (
                        <div className={s.clusterMeta}>
                          <span>Avg Return:</span>
                          <span style={{
                            color: typeof performance === 'number' && performance >= 0 ? C.green : C.red,
                            fontFamily: tokens.font.mono,
                          }}>
                            {typeof performance === 'number' ? formatPct(performance) : performance}
                          </span>
                        </div>
                      )}
                      {members.length > 0 && (
                        <div className={s.clusterMembers}>
                          {members.map(m => (
                            <span key={m} className={s.clusterTag} style={{ borderColor: `${color}55`, color }}>
                              {m}
                            </span>
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            ) : (
              <div className={s.emptyText}>No cluster data available</div>
            )}
          </div>

          {/* Risk Budgets */}
          <div className={s.panel}>
            <div className={s.panelTitle}>Risk Budgets</div>
            <div className={s.panelDescription}>
              Per-bot and per-strategy risk budget allocations from the risk management system.
            </div>
            {budgetEntries.length > 0 ? (
              budgetEntries.map((entry, i) => {
                const name = entry.name || entry.bot || entry.strategy || `Budget ${i + 1}`;
                const budget = entry.budget || entry.risk_budget || entry.max_risk || 0;
                const used = entry.used || entry.current_risk || 0;
                const budgetPct = budget > 1 ? budget : budget * 100;
                const usedPct = used > 1 ? used : used * 100;
                const utilization = budgetPct > 0 ? (usedPct / budgetPct) * 100 : 0;
                const barColor = utilization > 80 ? C.red : utilization > 60 ? C.amber : C.green;
                return (
                  <div key={name} className={s.riskBotRow}>
                    <span className={s.riskBotName} style={{ color: CLUSTER_COLORS[i % CLUSTER_COLORS.length] }}>{name}</span>
                    <div className={s.riskBarTrack}>
                      <div className={s.riskBarFill} style={{
                        backgroundColor: barColor,
                        width: `${Math.min(utilization, 100)}%`,
                      }} />
                    </div>
                    <span className={s.riskBotPct}>
                      {usedPct.toFixed(1)}% / {budgetPct.toFixed(1)}%
                    </span>
                  </div>
                );
              })
            ) : (
              <div className={s.emptyText}>No risk budget data available</div>
            )}
          </div>

          {/* Strategy Detail Lookup */}
          <div className={s.panel}>
            <div className={s.panelTitleSmall}>Strategy Detail Lookup</div>
            <div className={s.panelDescription}>
              Look up allocation details for a specific strategy.
            </div>
            <div style={{ display: 'flex', gap: 12, alignItems: 'flex-end', marginBottom: 16 }}>
              <div>
                <div className={s.transferFieldLabel}>Strategy Name</div>
                {allStrategyNames.length > 0 ? (
                  <select
                    value={selectedStrategy}
                    onChange={e => handleStrategyLookup(e.target.value)}
                    className={s.inputSelect}
                    style={{ width: 220 }}
                  >
                    <option value="">Select a strategy</option>
                    {allStrategyNames.map(n => (
                      <option key={n} value={n}>{n}</option>
                    ))}
                  </select>
                ) : (
                  <input
                    type="text"
                    value={selectedStrategy}
                    onChange={e => setSelectedStrategy(e.target.value)}
                    placeholder="Enter strategy name"
                    className={s.inputWide}
                    style={{ width: 220 }}
                    onKeyDown={e => { if (e.key === 'Enter') handleStrategyLookup(selectedStrategy); }}
                  />
                )}
              </div>
              {allStrategyNames.length === 0 && (
                <button
                  onClick={() => handleStrategyLookup(selectedStrategy)}
                  disabled={!selectedStrategy || strategyLoading}
                  className={s.saveBtn}
                  style={{ backgroundColor: selectedStrategy ? C.blue : C.surface2, color: selectedStrategy ? '#fff' : C.textSecondary, padding: '8px 16px' }}
                >
                  {strategyLoading ? 'Loading...' : 'Lookup'}
                </button>
              )}
            </div>

            {strategyLoading && (
              <div className={s.emptyText}>Loading strategy details...</div>
            )}

            {strategyDetail && !strategyLoading && (
              <div className={s.strategyDetailGrid}>
                {Object.entries(strategyDetail).filter(([k]) => k !== 'error' && k !== 'detail').map(([key, val]) => (
                  <div key={key} className={s.strategyDetailItem}>
                    <div className={s.strategyDetailLabel}>
                      {key.replace(/_/g, ' ')}
                    </div>
                    <div className={s.strategyDetailValue}>
                      {typeof val === 'number'
                        ? (key.includes('pct') || key.includes('rate') || key.includes('weight') || key.includes('allocation')
                          ? formatPct(val > 1 ? val / 100 : val)
                          : val.toFixed(4))
                        : typeof val === 'object'
                          ? JSON.stringify(val, null, 2)
                          : String(val)}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </LoadingState>
  );
}
